SELECT COUNT(*) AS total_secondary_navigation_menus
FROM menu_accessibility
WHERE aria_label = 'Secondary navigation';

SELECT theme_name
FROM menu_themes
WHERE menu_id = 1;

SELECT theme_name
FROM menu_themes
WHERE theme_id = 1;

SELECT menu_id, button_class_name
FROM dropdown_menus
WHERE border = 1 AND responsive_design = 1;

SELECT project_name
FROM projects
ORDER BY project_name;

SELECT COUNT(*) AS total_issues_reported
FROM component_issues
WHERE reported_by = 1;

SELECT developer_name
FROM developers
WHERE developer_id IN (
  SELECT reported_by
  FROM component_issues
);

SELECT template_name
FROM menu_templates
WHERE template_type = 'Default';

SELECT aria_label
FROM menu_accessibility
WHERE menu_id = 0;

SELECT project_name
FROM projects
WHERE project_status = 'In Progress';
